    for (Integer x : arr) {
        counts.set(x,counts.get(x)+1);
    }
    ArrayList<Integer> sorted_arr = new ArrayList<Integer>(100);
    for (Integer i = 0; i < counts.size(); i++) {
        sorted_arr.addAll(Collections.nCopies(counts.get(i),i));
